patch_segments.insert_text:
.evaluate-preface{margin:1.4rem 0 1.6rem;padding:0.85rem 1.05rem 0.95rem;border:1px solid var(--border);border-left:3px solid var(--ink-3);border-radius:6px;background:var(--card-bg)}
.evaluate-preface .ep-heading{font-family:var(--sans);font-size:0.82rem;text-transform:uppercase;letter-spacing:0.06em;color:var(--ink-3);margin:0 0 0.2rem;font-weight:600;border:none;padding:0}
.evaluate-preface .ep-caption{font-family:var(--sans);font-size:0.85rem;color:var(--ink-2);margin:0 0 0.7rem}
.evaluate-preface .ep-caption .ep-jump{color:var(--accent);text-decoration:none;font-weight:600}
.evaluate-preface .ep-caption .ep-jump:hover,.evaluate-preface .ep-caption .ep-jump:focus-visible{text-decoration:underline}
.evaluate-preface .ep-rows{list-style:none;margin:0;padding:0}
.evaluate-preface .ep-row{display:grid;grid-template-columns:1.5rem minmax(0,1fr) auto;gap:0.45rem 0.9rem;align-items:baseline;padding:0.5rem 0;border-top:1px solid var(--border)}
.evaluate-preface .ep-row:first-child{border-top:none;padding-top:0.2rem}
.evaluate-preface .ep-num{font-family:var(--sans);font-size:0.78rem;font-weight:700;color:var(--ink-3);font-variant-numeric:tabular-nums;text-align:right;line-height:1.4}
.evaluate-preface .ep-q{font-family:var(--serif);color:var(--heading);font-size:0.95rem;line-height:1.4;text-decoration:none;font-weight:500}
.evaluate-preface .ep-q:hover,.evaluate-preface .ep-q:focus-visible{color:var(--accent);text-decoration:underline}
.evaluate-preface .ep-where{font-family:var(--sans);font-size:0.72rem;text-transform:uppercase;letter-spacing:0.06em;color:var(--ink-3);font-weight:600;justify-self:end;text-align:right;line-height:1.3;white-space:nowrap}
@media(max-width:720px){.evaluate-preface .ep-row{grid-template-columns:1.4rem minmax(0,1fr);grid-template-areas:"num q" ". where";gap:0.2rem 0.6rem}.evaluate-preface .ep-num{grid-area:num}.evaluate-preface .ep-q{grid-area:q;font-size:0.92rem}.evaluate-preface .ep-where{grid-area:where;justify-self:start;text-align:left;font-size:0.7rem;white-space:normal}}
